python3 - <<'PY'
import json
path="ai-artifacts/01-framing/2026-06-18_claude_discussion-learn-coverage-policy.jsonl"
rows=[]
with open(path) as f:
    for ln in f:
        ln=ln.strip()
        if not ln: continue
        try: rows.append(json.loads(ln))
        except: pass

def textparts(content):
    out=[]
    if isinstance(content,str): return content
    if isinstance(content,list):
        for b in content:
            if not isinstance(b,dict): continue
            t=b.get("type")
            if t=="text": out.append(b.get("text",""))
            elif t=="thinking": out.append("[THINKING]\n"+b.get("thinking",""))
            elif t=="tool_use": out.append(f"[tool_use:{b.get('name')}]")
    return "\n".join(x for x in out if x)

seq=[]
for r in rows:
    msg=r.get("message")
    if not isinstance(msg,dict): continue
    role=msg.get("role")
    txt=textparts(msg.get("content"))
    if txt and txt.strip():
        seq.append((role,txt))

with open("/tmp/discussion_arc.md","w") as out:
    for i,(role,txt) in enumerate(seq):
        if len(txt) < 60:  # skip tiny acks/interrupts
            continue
        out.write(f"\n\n{'='*90}\n[{i}] {role.upper()} ({len(txt)} chars)\n{'='*90}\n")
        out.write(txt)
print("wrote /tmp/discussion_arc.md")
import os
print("size:", os.path.getsize("/tmp/discussion_arc.md"))
