export const meta = {
  name: 'framing-trajectory-audit',
  description: 'Adversarial panel: is the insurance take-home framing session drifting or on a good trajectory?',
  phases: [
    { title: 'Panel', detail: 'three distinct lenses judge the trajectory in parallel' },
  ],
}

const SCHEMA = {
  type: 'object',
  additionalProperties: false,
  required: ['lens', 'verdict', 'evidence_for_drift', 'evidence_for_on_track', 'the_one_risk', 'recommended_correction'],
  properties: {
    lens: { type: 'string' },
    verdict: { type: 'string', enum: ['on_track', 'minor_drift', 'significant_drift'] },
    evidence_for_drift: { type: 'array', items: { type: 'string' }, description: 'concrete, cite files/decisions' },
    evidence_for_on_track: { type: 'array', items: { type: 'string' } },
    the_one_risk: { type: 'string', description: 'the single biggest risk to flag, one sentence' },
    recommended_correction: { type: 'string', description: 'one concrete next-step correction, or "none — proceed" if truly on track' },
  },
}

const SHARED = `
CONTEXT — You are auditing the trajectory of a framing/design session for a take-home assignment.

The assignment (READ IT): project-docs/problem_statement.md and project-docs/candidate_assignment_instructions.md.
It is a 24-48h FDE take-home: build a claims-processing system; "a system that does 3 things well beats one that does 10 poorly"; rubric = domain decomposition, rule representation, state management, edge cases, explanation.

The framing work so far (READ THESE):
- /tmp/discussion_arc.md  — the full grilling+brainstorming discussion transcript (the thing under audit)
- PRD.md
- TRACK.md  — live cross-session memory: decisions log, open questions Q4/Q5, current focus
- docs/domain-model.md, docs/decisions.md
- ai-artifacts/01-framing/coverage-model-framing.md
- ai-artifacts/02-domain-research/coverage-rules-research.md

Where things stand: scaffold committed, ZERO application code written yet (repo rule: first code must arrive via a TDD cycle, test-first). Framing has locked: TS+SQLite+vitest, integer cents, cost-share discriminated union (full_coverage|copay|coinsurance), unit-typed limits (none|dollars|visits), 12-rule seed set, reimbursement payment model, Member as opaque member_id anchor. Actors-Actions-Artifacts walk: Policy + CoverageRule + Member locked, Claim is next, Q4 (dispute) + Q5 (duplicate) still open.

The user's question: "am I drifting or on a good trajectory?" The user's own stated north-star fear (quote from transcript turn 0): "leaving what the company wants we focus on solving the problem."

Be concrete and cite specific decisions/files. Do not be diplomatic — give a real verdict.
`

const LENSES = [
  {
    label: 'scope-creep-skeptic',
    prompt: `${SHARED}

YOUR LENS — SCOPE-CREEP / GOLD-PLATING SKEPTIC. Argue the case that this framing is over-engineering a 24-48h take-home and drifting from the brief. Press hard on: Is the discriminated union + unit-typed limits + OOP max + prior-auth + accumulators + dual state machines + immutable adjudication history + dispute re-adjudication MORE than "3 things done well"? The brief literally names only covered/excluded/dollar-limit/deductible. Is the team building a realistic insurance model the brief never asked for? Is time being burned on framing docs (6 artifacts, multi-agent research) instead of the working system that is deliverable #1? Where is the YAGNI line and has it been crossed? Be the harshest honest critic. Then return your structured verdict.`,
  },
  {
    label: 'analysis-paralysis-critic',
    prompt: `${SHARED}

YOUR LENS — PROCESS / MOMENTUM / ANALYSIS-PARALYSIS CRITIC. Ignore whether the MODEL is good; judge the PROCESS and velocity. Concrete facts to weigh: substantial framing depth, multiple skills invoked (grill-me, insurance-domain, agent-reach/research, brainstorming), 6 artifact files, full decision log — and still ZERO lines of application code, no tests, no running system. The brief is 24-48h and deliverable #1 is "a working system." Is the user converging or expanding scope each session? Is "walk the Actors-Actions-Artifacts map one noun at a time" a disciplined method or a way to defer ever shipping code? Is the test-first rule being used as a reason to keep talking? Quantify how much of the 24-48h budget framing should consume and whether this is past it. Be the harshest honest critic on momentum. Then return your structured verdict.`,
  },
  {
    label: 'domain-correctness-defender',
    prompt: `${SHARED}

YOUR LENS — DOMAIN-CORRECTNESS & METHOD DEFENDER. Argue the case that this trajectory is excellent. Assess: Is the depth-first focus on the adjudication engine the RIGHT bet given the rubric calls adjudication "the interesting problem"? Are the modeling decisions (discriminated union, unit-typed limits, integer cents, immutable adjudication, derived claim status) genuinely domain-correct and defensible under live questioning in the next round? Is grounding decisions in real-insurer research a strength a reviewer will reward? Is the discipline of locking concepts before schema/code actually de-risking the build? Is the artifact trail itself a deliverable (the brief mandates AI-collaboration artifacts + JSONL logs + decisions doc)? Steelman the trajectory honestly — but still name the one real risk you see. Then return your structured verdict.`,
  },
]

const verdicts = await parallel(
  LENSES.map(l => () => agent(l.prompt, { label: l.label, phase: 'Panel', schema: SCHEMA }))
)

return { verdicts: verdicts.filter(Boolean) }

